-- Create the tenant catalog before adding tenant ownership to existing rows.
CREATE TABLE "tenants" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "key" character varying NOT NULL,
  "name" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'active',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX "tenant_key" ON "tenants" ("key");
CREATE INDEX "tenant_status_name" ON "tenants" ("status", "name");

-- Every pre-existing row belongs to the compatibility tenant. PostgreSQL stores
-- constant ADD COLUMN defaults as metadata, so this backfill does not rewrite
-- populated tables. The defaults are removed immediately to keep future writes
-- fail-closed when application code omits tenant ownership.
INSERT INTO "tenants" ("id", "key", "name", "status", "created_at", "updated_at")
VALUES (1, 'default', 'Default', 'active', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
SELECT setval(pg_get_serial_sequence('tenants', 'id'), 1, true);

