-- Tenant memberships are empty on upgrade. The compatibility tenant remains
-- accessible to authenticated users until explicit memberships are configured.
CREATE TABLE "tenant_memberships" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject" character varying NOT NULL,
  "role" character varying NOT NULL DEFAULT 'member',
  "enabled" boolean NOT NULL DEFAULT true,
  "created_by" character varying NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "tenant_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "tenant_memberships_tenants_tenant" FOREIGN KEY ("tenant_id") REFERENCES "tenants" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX "tenantmembership_subject_enabled" ON "tenant_memberships" ("subject", "enabled");
CREATE INDEX "tenantmembership_tenant_id_enabled" ON "tenant_memberships" ("tenant_id", "enabled");
CREATE UNIQUE INDEX "tenantmembership_tenant_id_subject" ON "tenant_memberships" ("tenant_id", "subject");
